when.condition:
@{
              var authHeader = context.Request.Headers.GetValueOrDefault("Authorization", "");
              var rawToken = authHeader.StartsWith("Bearer ") ? authHeader.Substring(7) : authHeader;

              var jwt = rawToken.AsJwt();

              var upn = (jwt?.Claims.GetValueOrDefault("upn") ?? "").ToLower();
              var preferred = (jwt?.Claims.GetValueOrDefault("preferred_username") ?? "").ToLower();

              var user = !string.IsNullOrEmpty(upn) ? upn : preferred;

              return user != "p_admin@stephanieirinaexternaloutlo.onmicrosoft.com";
          }
